//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
  // 세션 정보
  let memJson = $c.data.getMemInfo($p);
  scwin.userId = memJson.userId;
  scwin.p_lobranCd = $c.data.getMemInfo($p, "lobranCd") || ""; // 귀속부서코드
  scwin.p_lobranNm = $c.data.getMemInfo($p, "lobranNm"); // 귀속부서 명

  //default 동부국제물류
  var resData = await $c.gus.dsCommonUtil($p, "getCompanyInfoDTO", scwin.p_lobranCd)[0]?.value.split("\n");
  var commDTO = resData.reduce((acc, curr) => {
    let match = curr.match(/^\s*\w+\s+(\w+)\s+=\s+\[(.*)\]/);
    if (match) {
      let key = match[1];
      let value = match[2];
      if (value == "null") value = null;
      acc[key] = value;
    }
    return acc;
  }, {});
  scwin.p_clntNo = commDTO.clntNo || "";
  scwin.p_seaExgbEx = commDTO.seaExgbEx || "";
  scwin.v_linkcheck = $c.data.getParameter($p, "linkcheck") || "";
  scwin.v_kcomcd = $c.data.getParameter($p, "kcomcd") || "";
  scwin.v_blno = $c.data.getParameter($p, "blno") || "";
  scwin.v_mhno = $c.data.getParameter($p, "mhno") || "";
  scwin.v_bkno = $c.data.getParameter($p, "bkno") || "";
  scwin.p_no = $c.data.getParameter($p, "no") || "";
  scwin.p_row_cnt = $c.data.getParameter($p, "row_cnt") || "";
  scwin.p_data = $c.data.getParameter($p, "data") || "";
  scwin.p_hblno = $c.data.getParameter($p, "hblno") || "";
  scwin.p_docuno = $c.data.getParameter($p, "docuno") || "";

  // 서버일자
  scwin.strCurDate = $c.date.getServerDateTime($p, "yyyyMMdd");
  scwin.f_initSetTab(); //tab세팅	
  scwin.f_DefaultValue();
  scwin.f_ContainerTypeLoading(); // Container Type 정보 
  scwin.f_CurrencyLoading(); //환율 코드 정보.
  scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리 
};

//---------------------------------------------------------
// Parameter Setting (WebSquare 표준 정리)
// - 컴포넌트 방어코드 제거
// - DataList API 통일: getRowCount / insertRow / setCellData
//---------------------------------------------------------
scwin.f_getParametrSetting = async function (gubun) {
  switch (gubun) {
    case "0":
      break;
    case "5":
      // House B/L에서 옴.
      scwin.mhnoFlag = "1";
      if ($c.gus.cfIsNull($p, scwin.v_blno)) {
        cnd_ed_hhblno.setValue("");
        cnd_ed_hhblno.focus();
        return false;
      }
      scwin.hd_kcomcd = scwin.v_kcomcd;
      cnd_ed_hhblno.setValue(scwin.v_blno);
      if (ds_hmhno.getRowCount() == 0) {
        ds_hmhno.insertRow(0);
      }
      const row = ds_hmhno.getRowCount() - 1;
      ds_hmhno.setCellData(row, "code", scwin.v_mhno);
      ds_hmhno.setCellData(row, "name", scwin.v_mhno);
      cnd_lc_mhno.focus();
      break;
    case "9":
      scwin.mhnoFlag = "1";
      cnd_ed_hhblno.setValue(scwin.p_hblno);
      if (ds_hmhno.getRowCount() == 0) {
        ds_hmhno.insertRow(0);
      }
      const r2 = ds_hmhno.getRowCount() - 1;
      ds_hmhno.setCellData(r2, "code", scwin.p_docuno);
      ds_hmhno.setCellData(r2, "name", scwin.p_docuno);
      cnd_lc_mhno.focus();
      break;
    default:
      break;
  }
  return true;
};

