//---------------------------------------------------------
// 화면상태 세팅
//--------------------------------------------------------- 
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      // 초기화
      $c.gus.cfDisableKeyData($p); // Key와 Data를 모두 disable(non-editable)
      $c.gus.cfDisableBtnOnly($p, [btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_1, btn_3, btn_4, btn_5, btn_6, btn_exChg, btn_cusChg, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2, btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3]);
      $c.gus.cfEnableBtnOnly($p, [btn_7]);
      scwin.f_DisablePopUpObj();
      $c.gus.cfEnableObjects($p, [tbl_searchCondition, tbl_searchCondition2]); // 조회조건
      scwin.statusFlag = "I";
      break;
    case "RETRIEVE":
      // 조회모드
      $c.gus.cfDisableKeyData($p);
      scwin.f_DisablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel, btn_1, btn_exChg, btn_cusChg, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2, btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3]);
      $c.gus.cfEnableBtnOnly($p, [btn_Delete, btn_3, btn_4, btn_5, btn_6, btn_7]);

      // 그리드 수정 불가
      // gr_selling.readOnly = true;
      // gr_partner.readOnly = true;
      // gr_buying.readOnly = true;

      scwin.f_setGridColumnsReadOnly(gr_selling, true);
      scwin.f_setGridColumnsReadOnly(gr_partner, true);
      scwin.f_setGridColumnsReadOnly(gr_buying, true);
      if (scwin.statusFlag == "C") {
        $c.gus.cfDisableBtnOnly($p, [btn_Update]);
      } else {
        $c.gus.cfEnableBtnOnly($p, [btn_Update]);
      }
      $c.gus.cfEnableObjects($p, [tbl_searchCondition, tbl_searchCondition2]); // 조회조건
      scwin.statusFlag = "";
      break;
    case "CREATE":
      // 신규
      $c.gus.cfEnableKeyData($p);
      scwin.f_EnablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Update, btn_Delete, btn_3, btn_4, btn_5, btn_6]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_1, btn_7, btn_exChg, btn_cusChg, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2, btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3]);

      // 그리드 수정 가능
      // gr_selling.readOnly = false;
      // gr_partner.readOnly = false;
      // gr_buying.readOnly = false;

      scwin.f_setGridColumnsReadOnly(gr_selling, false);
      scwin.f_setGridColumnsReadOnly(gr_partner, false);
      scwin.f_setGridColumnsReadOnly(gr_buying, false);
      $c.gus.cfDisableObjects($p, [tbl_searchCondition, tbl_searchCondition2]); // 조회조건
      scwin.statusFlag = "C";
      break;
    case "UPDATE":
      $c.gus.cfDisableBtnOnly($p, [btn_Update, btn_Delete, btn_3, btn_4, btn_5, btn_6]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_1, btn_7, btn_exChg, btn_cusChg, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2, btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3]);
      $c.gus.cfDisableKey($p);
      scwin.f_EnablePopUpObj();

      // 그리드 수정 가능
      // gr_selling.Editable  = "true";
      // gr_partner.Editable  = "true"; 
      // gr_buying.Editable  = "true";  
      scwin.f_setGridColumnsReadOnly(gr_selling, false);
      scwin.f_setGridColumnsReadOnly(gr_partner, false);
      scwin.f_setGridColumnsReadOnly(gr_buying, false);
      $c.gus.cfDisableObjects($p, [tbl_searchCondition, tbl_searchCondition2]); // 조회조건
      scwin.statusFlag = "U";
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Delete, btn_Cancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};

