//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (ds_houseblList.getModifiedIndex().length > 0 || ds_selling.getModifiedIndex().length > 0 || ds_partner.getModifiedIndex().length > 0 || ds_buying.getModifiedIndex().length > 0) {
    if ((await scwin.f_validate()) && (await scwin.f_JobCloseYn())) {
      if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
        //저장하시겠습니까?	
        if (scwin.statusFlag == "C") {
          if (ds_houseblList.getRowCount() == 0) ds_houseblList.insertRow(0);
          var r = ds_houseblList.getRowPosition();
          ds_houseblList.setValue(r, "kcomcd", scwin.hd_kcomcd);
          ds_houseblList.setValue(r, "hhblno", cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : "");
          ds_houseblList.setValue(r, "mhno", cnd_lc_mhno ? cnd_lc_mhno.getValue() : "");
          ds_houseblList.setValue(r, "hhio", scwin.hd_hhio);
          ds_houseblList.setValue(r, "inpid", scwin.userId);
        }
        scwin.v_linkcheck = "";
        var e = await $c.sbm.execute($p, sbm_save);
        if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
          await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
          $c.gus.cfEnableObj($p, cnd_ed_hhblno, true);
          $c.gus.cfEnableObj($p, cnd_lc_mhno, true);
          await scwin.f_Retrieve();
          scwin.f_Set("SAVE");
        }
      }
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["House B/L Freight"]); // @은(는) 변경된 사항이 없습니다.
  }
};

