    ds_partner.setCellData(row, "rsltsStdDt", "");
    ds_partner.setCellData(row, "exRateTyp", "");
    ds_partner.setCellData(row, "sellUpr", g_Rate2);
    ds_partner.setCellData(row, "exRate", g_Ex_Rate2);
    ds_partner.setCellData(row, "sellAmtFcrc", g_Amount2);
    ds_partner.setCellData(row, "sellAmt", g_Amount_W2);
    ds_partner.setCellData(row, "usdAmt", g_Amount_US2);
    await scwin.f_partnerUnitLoading();
