//-------------------------------------------------------------------------
// 다중 행 추가 (disGubun: 1 Selling, 2 Partner, 3 Buying) - WebSquare 안정화 버전
//-------------------------------------------------------------------------
scwin.f_addRowMulti = async function (disGubun) {
  // BL 체크 (1회)
  var blNo = cnd_ed_hhblno && cnd_ed_hhblno.getValue ? String(cnd_ed_hhblno.getValue() || "").trim() : "";
  if (!blNo) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
    return;
  }

  // 행 생성 개수 (공백/NaN 방어)
  function toCnt(comp, defVal) {
    var v = comp && comp.getValue ? String(comp.getValue() || "").trim() : "";
    var n = parseInt(v, 10);
    return isNaN(n) || n < 1 ? defVal : n;
  }

  // odrNo
  var odrNo = "";
  if (ds_houseblList && ds_houseblList.getRowCount && ds_houseblList.getRowCount() > 0) {
    var hp = ds_houseblList.getRowPosition();
    odrNo = String(ds_houseblList.getCellData(hp, "odrNo") || "");
  }

  // 현재행 다음 insert / 마지막이면 append (GAUCE 느낌)
  function insertLikeGauce(ds) {
    var rc = ds.getRowCount();
    var rp = ds.getRowPosition(); // 0-based
    var idx;
    if (rc == 0) {
      idx = 0;
    } else if (rp == rc - 1) {
      // 마지막행이면 append
      idx = rc;
    } else {
      // 아니면 다음행에 insert
      idx = rp + 1;
    }
    ds.insertRow(idx);
    ds.setRowPosition(idx);
    return idx;
  }

  // 공통 값
  var mhnoCd = String(cnd_lc_mhno.getValue() || "");
  var kcomcd = scwin.hd_kcomcd || "";
  var ppccCls = scwin.hd_hhpcgb || "";
  var rsltsStdDt = scwin.hd_creadyDt || "";
  var exRateTyp = lc_hhexgb.getValue();
  var userId = scwin.userId || "";

  // 현재행의 특정 컬럼 값을 복사 (없으면 0)
  function curNum(ds, colId) {
    if (!ds || ds.getRowCount() == 0) return 0;
    var rp = ds.getRowPosition();
    var v = ds.getCellData(rp, colId);
    return v == "" || v == null || v == undefined ? 0 : v;
  }

  //==========================
  // 1) SELLING
  //==========================
  if (disGubun == 1) {
    var rowMake_selling = toCnt(ed_rowMake_selling, 1);

    // 루프 전에 UNIT 목록 1회 로딩 (비동기 보장)
    let defaultUnit = "";
    if (scwin.f_sellingUnitLoading) {
      // f_sellingUnitLoading 내부에서 scwin.f_commCode를 호출하고,
      // scwin.f_commCode는 await $c.sbm.execute(...) 하도록 바꿨으니 await 가능
      await scwin.f_sellingUnitLoading();
      if (ds_sellingUnit && ds_sellingUnit.getRowCount() > 0) {
        defaultUnit = String(ds_sellingUnit.getCellData(0, "code") || "");
      }
    }
    for (var i = 0; i < rowMake_selling; i++) {
      var g_Rate = curNum(ds_selling, "sellUpr");
      var g_Ex_Rate = curNum(ds_selling, "exRate");
      var g_Amount = curNum(ds_selling, "sellAmtFcrc");
      var g_Amount_W = curNum(ds_selling, "sellAmt");
      var g_Amount_US = curNum(ds_selling, "usdAmt");
      var row = insertLikeGauce(ds_selling);
      ds_selling.setCellData(row, "kcomcd", kcomcd);
      ds_selling.setCellData(row, "blNo", blNo);
      ds_selling.setCellData(row, "mhno", mhnoCd);
      ds_selling.setCellData(row, "odrNo", odrNo);
      ds_selling.setCellData(row, "locPtnCls", "1");
      ds_selling.setCellData(row, "mblHblCls", "H");
      ds_selling.setCellData(row, "seaAirCls", "S");
      ds_selling.setCellData(row, "drcrCls", "D");
      ds_selling.setCellData(row, "ppccCls", ppccCls);
      ds_selling.setCellData(row, "inpid", userId);
      ds_selling.setCellData(row, "bilgClntNo", ed_hhactcust && ed_hhactcust.getValue ? ed_hhactcust.getValue() : "");
      ds_selling.setCellData(row, "bilgClntNm", txt_hhactcustnm.getValue() || "");
      ds_selling.setCellData(row, "rsltsStdDt", rsltsStdDt);
      ds_selling.setCellData(row, "exRateTyp", exRateTyp);
      ds_selling.setCellData(row, "sellUpr", g_Rate);
      ds_selling.setCellData(row, "exRate", g_Ex_Rate);
      ds_selling.setCellData(row, "sellAmtFcrc", g_Amount);
      ds_selling.setCellData(row, "sellAmt", g_Amount_W);
      ds_selling.setCellData(row, "usdAmt", g_Amount_US);

      //unit처리.
      await scwin.f_sellingUnitLoading();
      ds_selling.setCellData(row, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
      scwin.f_packageRateSellingLoading(row, '');
      gr_selling.setFocusedCell(row, "fareEngCd", true);
    }
    return;
  }

  //==========================
  // 2) PARTNER
  //==========================
  if (disGubun == 2) {
    var rowMake_partner = toCnt(ed_rowMake_partner, 1);

    // 루프 전에 UNIT 목록 1회 로딩 (비동기 보장)
    let defaultUnit = "";
    if (scwin.f_partnerUnitLoading) {
      // scwin.f_commCode는 await $c.sbm.execute(...) 하도록 바꿨으니 await 가능
      await scwin.f_partnerUnitLoading();
      if (ds_partnerUnit && ds_partnerUnit.getRowCount() > 0) {
        defaultUnit = String(ds_partnerUnit.getCellData(0, "code") || "");
      }
    }
    for (var j = 0; j < rowMake_partner; j++) {
      var g_Rate2 = curNum(ds_partner, "sellUpr");
      var g_Ex_Rate2 = curNum(ds_partner, "exRate");
      var g_Amount2 = curNum(ds_partner, "sellAmtFcrc");
      var g_Amount_W2 = curNum(ds_partner, "sellAmt");
      var g_Amount_US2 = curNum(ds_partner, "usdAmt");
      var row2 = insertLikeGauce(ds_partner);
      ds_partner.setCellData(row2, "kcomcd", kcomcd);
      ds_partner.setCellData(row2, "blNo", blNo);
      ds_partner.setCellData(row2, "mhno", mhnoCd);
      ds_partner.setCellData(row2, "odrNo", odrNo);
      ds_partner.setCellData(row2, "drcrCls", "D");
      ds_partner.setCellData(row2, "locPtnCls", "2");
      ds_partner.setCellData(row2, "mblHblCls", "H");
      ds_partner.setCellData(row2, "seaAirCls", "S");
      ds_partner.setCellData(row2, "ppccCls", ppccCls);
      ds_partner.setCellData(row2, "inpid", userId);
      ds_partner.setCellData(row2, "bilgClntNo", ed_hhagent && ed_hhagent.getValue ? ed_hhagent.getValue() : "");
      ds_partner.setCellData(row2, "bilgClntNm", txt_hhagentnm.getValue());
      ds_partner.setCellData(row2, "rsltsStdDt", rsltsStdDt);
      ds_partner.setCellData(row2, "exRateTyp", exRateTyp);
      ds_partner.setCellData(row2, "sellUpr", g_Rate2);
      ds_partner.setCellData(row2, "exRate", g_Ex_Rate2);
      ds_partner.setCellData(row2, "sellAmtFcrc", g_Amount2);
      ds_partner.setCellData(row2, "sellAmt", g_Amount_W2);
      ds_partner.setCellData(row2, "usdAmt", g_Amount_US2);

      //unit처리.
      await scwin.f_partnerUnitLoading();
      ds_partner.setCellData(row2, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
      scwin.f_packageRatePartnerLoading(row2, '');
      gr_partner.setFocusedCell(row2, "fareEngCd", true);
    }
    return;
  }

  //==========================
  // 3) BUYING
  //==========================
  if (disGubun == 3) {
    var rowMake_buying = toCnt(ed_rowMake_buying, 1);

    // 루프 전에 UNIT 목록 1회 로딩 (비동기 보장)
    let defaultUnit = "";
    if (scwin.f_buyingUnitLoading) {
      // scwin.f_commCode는 await $c.sbm.execute(...) 하도록 바꿨으니 await 가능
      await scwin.f_buyingUnitLoading();
      if (ds_buyingUnit && ds_buyingUnit.getRowCount() > 0) {
        defaultUnit = String(ds_buyingUnit.getCellData(0, "code") || "");
      }
    }
    for (var k = 0; k < rowMake_buying; k++) {
      var g_Rate3 = curNum(ds_buying, "pchsUpr");
      var g_Ex_Rate3 = curNum(ds_buying, "exRate");
      var g_Amount3 = curNum(ds_buying, "pchsAmtFcrc");
      var g_Amount_W3 = curNum(ds_buying, "pchsAmt");
      var g_Amount_US3 = curNum(ds_buying, "usdAmt");
      var row3 = insertLikeGauce(ds_buying);
      ds_buying.setCellData(row3, "kcomcd", kcomcd);
      ds_buying.setCellData(row3, "blNo", blNo);
      ds_buying.setCellData(row3, "mhno", mhnoCd);
      ds_buying.setCellData(row3, "odrNo", odrNo);
      ds_buying.setCellData(row3, "locPtnCls", "1");
      ds_buying.setCellData(row3, "mblHblCls", "H");
      ds_buying.setCellData(row3, "seaAirCls", "S");
      ds_buying.setCellData(row3, "drcrCls", "C");
      ds_buying.setCellData(row3, "ppccCls", ppccCls);
      ds_buying.setCellData(row3, "inpid", userId);
      ds_buying.setCellData(row3, "pchsClntNo", ed_hhliner.getValue() || "");
      ds_buying.setCellData(row3, "pchsClntNm", txt_hhlinernm.getValue() || "");
      ds_buying.setCellData(row3, "rsltsStdDt", rsltsStdDt);
      ds_buying.setCellData(row3, "exRateTyp", exRateTyp);
      ds_buying.setCellData(row3, "pchsTyp", "1");
      ds_buying.setCellData(row3, "pchsUpr", g_Rate3);
      ds_buying.setCellData(row3, "exRate", g_Ex_Rate3);
      ds_buying.setCellData(row3, "pchsAmtFcrc", g_Amount3);
      ds_buying.setCellData(row3, "pchsAmt", g_Amount_W3);
      ds_buying.setCellData(row3, "usdAmt", g_Amount_US3);

      //unit처리.
      await scwin.f_buyingUnitLoading();
      ds_buying.setCellData(row3, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
      scwin.f_packageRateBuyingLoading(row3, '');
      gr_buying.setFocusedCell(row3, "pchsTyp", false);
    }
    return;
  }
};
