// 공통 코드조회 (param1~4)
// - sysCd 생략 시 "ilCommonEBC" 기본
scwin.f_commCode = async function (sysCd, queryId, param1, param2, param3, param4) {
  // sysCd 생략 호출 허용: f_commCode("queryId", p1, p2 ...)
  if (queryId === undefined) {
    queryId = sysCd;
    sysCd = "ilCommonEBC";
    param4 = param3;
    param3 = param2;
    param2 = param1;
    param1 = "";
  }
  var params = {
    sysCd: sysCd || "ilCommonEBC",
    queryId: queryId || "",
    param1: param1 == undefined ? "" : param1,
    param2: param2 == undefined ? "" : param2,
    param3: param3 == undefined ? "" : param3,
    param4: param4 == undefined ? "" : param4
  };
  dma_combo.setEmptyValue();
  dma_combo.setJSON(params);
  $c.sbm.execute($p, sbm_combo);
};

//-------------------------------------------------------------------------
// sbm_combo onsubmitdone (정리/중복 제거 버전)
// - rs: 실제 응답 DataList명으로 교체 필요
//-------------------------------------------------------------------------
//-------------------------------------------------------------------------
// sbm_combo onsubmitdone (WebSquare)
//-------------------------------------------------------------------------
scwin._exRateTarget = "";
scwin.sbm_combo_onsubmitdone = async function (e) {
  //var rs = ds_combo; // ✅ 실제 응답 DataList로 변경

  //==========================
  // 1) MHNO(HH) 처리
  //==========================
  if (scwin._comboTarget == "HMHNO1") {
    ds_hmhno.setJSON(e.responseJSON.GAUCE);

    //  for=ds_hmhno event=OnLoadCompleted(rowcnt)
    if (ds_hmhno.getRowCount() == 0) {
      if (scwin.statusFlag != "C") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["House No"]); // ✅ 이제 에러 안남
      }
      var r0 = ds_hmhno.insertRow(0);
      ds_hmhno.setCellData(r0, "code", "NONE");
      ds_hmhno.setCellData(r0, "name", "NONE");
      if (cnd_lc_mhno && cnd_lc_mhno.setSelectedIndex) {
        cnd_lc_mhno.setSelectedIndex(0);
      } else if (cnd_lc_mhno && cnd_lc_mhno.setValue) {
        cnd_lc_mhno.setValue("NONE");
      }
    }
    if (scwin.mhnoFlag == "1") {
      scwin.f_Retrieve();
      scwin.mhnoFlag = "0";
    }
    scwin._comboTarget = "";
    return;
  }

  //==========================
  if (scwin._comboTarget == "HMHNO2") {
    ds_hmhno2.setJSON(e.responseJSON.GAUCE);
    // 비어있으면 NONE 세팅
    if (ds_hmhno2.getRowCount() == 0) {
      if (scwin.statusFlag != "C") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["House No"]); // ✅ 이제 에러 안남
      }
      var r0 = ds_hmhno2.insertRow(0);
      ds_hmhno2.setCellData(r0, "code", "NONE");
      ds_hmhno2.setCellData(r0, "name", "NONE");
      if (srch_ed_hhblno && srch_ed_hhblno.setSelectedIndex) {
        srch_ed_hhblno.setSelectedIndex(0);
      } else if (srch_ed_hhblno && srch_ed_hhblno.setValue) {
        srch_ed_hhblno.setValue("NONE");
      }
    }
    scwin._comboTarget = "";
    return;
  }

  //==========================
  // 1) INVOICE 처리
  //==========================
  if (scwin._comboTarget == "INVOICE") {
    ds_invoiceCheck.setJSON(e.responseJSON.GAUCE);
    if (ds_invoiceCheck.getCellData(ds_invoiceCheck.getRowPosition(), "code") != "0") {
      scwin.invoiceCheck = "1";
    }
    scwin._comboTarget = "";
  }

  //==========================
  // 1) SELLING_UNIT 처리
  //==========================
  if (scwin._comboTarget == "SELLING_UNIT") {
    ds_sellingUnit.setJSON(e.responseJSON.GAUCE);
    scwin._comboTarget = "";
  }

  //==========================
  // 1) INVOICE 처리
  //==========================
  if (scwin._comboTarget == "PARTNER_UNIT") {
    ds_partnerUnit.setJSON(e.responseJSON.GAUCE);
    scwin._comboTarget = "";
  }

  //==========================
  // 1) INVOICE 처리
  //==========================
  if (scwin._comboTarget == "BUYING_UNIT") {
    ds_buyingUnit.setJSON(e.responseJSON.GAUCE);
    scwin._comboTarget = "";
  }

  //tobe 추가
  if (scwin._comboTarget == 'CURRENCY') {
    ds_currencyCode.setJSON(e.responseJSON.GAUCE);
    scwin._comboTarget = "";
  }

  //tobe 추가
  if (scwin._comboTarget == "PARTER_CODE") {
    ds_ParterCode.setJSON(e.responseJSON.GAUCE);
    scwin._comboTarget = "";
  }

  //==========================
  // 2) exRateTarget 처리 (HOUSE/SELLING/BUYING/PARTNER)
  //==========================
  if (scwin._exRateTarget) {
    ds_exHouseRate.setJSON(e.responseJSON.GAUCE);
    var code2 = String(ds_exHouseRate.getCellData(0, "code") || "").trim();
    var name2 = String(ds_exHouseRate.getCellData(0, "name") || "").trim();
    if (scwin._exRateTarget == "HOUSE") {
      if (ed_hhexrate) ed_hhexrate.setValue(code2);
      if (ed_hhuexrate) ed_hhuexrate.setValue(name2);
      if (code2 == "" && scwin._exRateCur != "KRW") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Ex-Rate"]);
        scwin.exRateCheck = "1";
      } else {
        scwin.exRateCheck = "2";
        scwin.exRate1 = code2;
        scwin.exRate2 = name2;
        scwin.crc = scwin._exRateCur;
      }
    } else if (scwin._exRateTarget == "SELLING") {
      ds_selling.setCellData(scwin._exRateRow, "exRate", code2);
      if (code2 == "" && scwin._exRateCur != "KRW") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Ex-Rate"]);
      }
    } else if (scwin._exRateTarget == "BUYING") {
      ds_buying.setCellData(scwin._exRateRow, "exRate", code2);
      if (code2 == "" && scwin._exRateCur != "KRW") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Ex-Rate"]);
      }
    } else if (scwin._exRateTarget == "PARTNER") {
      ds_partner.setCellData(scwin._exRateRow, "exRate", code2);
      if (code2 == "" && scwin._exRateCur != "KRW") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Ex-Rate"]);
      }
    }
    scwin._exRateTarget = "";
    scwin._exRateRow = -1;
    scwin._exRateCur = "";
  }
};

