//-------------------------------------------------------------------------
// Tariff 관련
//-------------------------------------------------------------------------
//-------------------------------------------------------------------------
// TariffRate 공통 조회 (flag=2 고정)
// type: "SELLING" | "PARTNER" | "BUYING"
//-------------------------------------------------------------------------
scwin.f_tariffRateLoading = function (type) {
  // 현재행 체크
  var ds = null;
  var fgubn = "";
  var transTariffYn = "Y";
  if (type == "SELLING") {
    ds = ds_selling;
    fgubn = "1";
    transTariffYn = "Y";
  } else if (type == "PARTNER") {
    ds = ds_partner;
    fgubn = "3";
    transTariffYn = "N";
  } else if (type == "BUYING") {
    ds = ds_buying;
    fgubn = "2";
    transTariffYn = "Y";
  } else {
    return;
  }
  if (!ds || ds.getRowCount() == 0) return;
  var b = ds.getRowPosition();
  if (b < 0) return;

  // 파라미터 구성 (retrieve ds)
  ds_retrieveTariff.removeAll();
  ds_resultTariff.removeAll();
  ds_retrieveTariff.insertRow(0);

  // 공통 값
  var kcomcd = scwin.hd_kcomcd || "";
  var apdt = ed_hhetd ? ed_hhetd.getValue() : "";
  var item = scwin.hd_hhitem || "";
  var dang = scwin.hd_hhdanggb || "";
  var commcust = scwin.hd_commcustomer || "";
  var userId = scwin.userId || "";
  var loading = ed_hhlodcd ? ed_hhlodcd.getValue() : "";
  var discharge = ed_hhdisccd ? ed_hhdisccd.getValue() : "";

  // 고객/파트너/라이너 (type별)
  var customer = "";
  var partner = "";
  var liner = "";
  if (type == "SELLING" || type == "BUYING") {
    customer = ed_hhactcust ? ed_hhactcust.getValue() : "";
    liner = ed_hhliner ? ed_hhliner.getValue() : "";
  } else if (type == "PARTNER") {
    partner = ed_hhagent ? ed_hhagent.getValue() : "";
  }

  // fcode/currency/funit은 현재 선택행 기준
  var fcode = String(ds.getCellData(b, "fareEngCd") || "").trim();
  var currency = String(ds.getCellData(b, "crcCd") || "").trim();
  var funit = String(ds.getCellData(b, "fareUnit") || "").trim();

  // BL/MHNO (Partner는 원본처럼 공백)
  var blNo = "";
  var mhno = "";
  if (type != "PARTNER") {
    blNo = cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : "";
    mhno = cnd_lc_mhno ? cnd_lc_mhno.getValue() : "";
  }

  // ds_retrieveTariff set
  ds_retrieveTariff.setCellData(0, "fgubn", fgubn);
  ds_retrieveTariff.setCellData(0, "kcomcd", kcomcd);
  ds_retrieveTariff.setCellData(0, "apdt", apdt);
  ds_retrieveTariff.setCellData(0, "customer", customer);
  ds_retrieveTariff.setCellData(0, "partner", partner);
  ds_retrieveTariff.setCellData(0, "liner", liner);
  ds_retrieveTariff.setCellData(0, "loading", loading);
  ds_retrieveTariff.setCellData(0, "discharge", discharge);
  ds_retrieveTariff.setCellData(0, "item", item);
  ds_retrieveTariff.setCellData(0, "cbgubn", "C");
  ds_retrieveTariff.setCellData(0, "incoterm", "");
  ds_retrieveTariff.setCellData(0, "userid", userId);
  ds_retrieveTariff.setCellData(0, "dangerous", dang);
  ds_retrieveTariff.setCellData(0, "commcustomer", commcust);
  ds_retrieveTariff.setCellData(0, "fcode", fcode);
  ds_retrieveTariff.setCellData(0, "currency", currency);
  ds_retrieveTariff.setCellData(0, "funit", funit);
  ds_retrieveTariff.setCellData(0, "flag", "2"); // tariffRate
  ds_retrieveTariff.setCellData(0, "transTariffYn", transTariffYn);
  ds_retrieveTariff.setCellData(0, "blNo", blNo);
  ds_retrieveTariff.setCellData(0, "mhno", mhno);

  // submit done에서 어디에 꽂을지 저장
  scwin._tariffRateType = type;
  scwin._tariffRateRow = b;

  // submission 실행
  // 프로젝트에 맞는 submission ID로 교체해줘 (예: sbm_retrieveTariff)
  $c.sbm.execute($p, sbm_retrieveTariff);
};

