//-------------------------------------------------------------------------
// Tariff All 가져오기 (Selling/Partner/Buying 탭별 일괄 생성)
// - scwin.tabNo: "0"(Selling), "1"(Partner), "2"(Buying)
// - 대상 DS에 기존 데이터 있으면 경고 후 중단
// - confirm 후 진행
// - 결과 중 chgWt == "0" 행은 삭제
//-------------------------------------------------------------------------
scwin._tariffMode = "";
scwin.f_tariffAllLoading = async function () {
  function getCnt(typeComp, qtyComp) {
    var t = typeComp ? String(typeComp.getValue() || "").trim() : "";
    var q = qtyComp ? String(qtyComp.getValue() || "").trim() : "";
    if (t != "" && q != "" && q != "0") return t;
    return "0";
  }
  var cnt1 = getCnt(ed_hhcnt1type, ed_hhcnt1);
  var cnt2 = getCnt(ed_hhcnt2type, ed_hhcnt2);
  var cnt3 = getCnt(ed_hhcnt3type, ed_hhcnt3);
  var cnt4 = getCnt(ed_hhcnt4type, ed_hhcnt4);

  // 기존 데이터 존재 여부 체크
  if (scwin.tabNo == "0") {
    if (ds_selling && ds_selling.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Selling Information"]);
      return;
    }
  } else if (scwin.tabNo == "1") {
    if (ds_partner && ds_partner.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Partner Information"]);
      return;
    }
  } else if (scwin.tabNo == "2") {
    if (ds_buying && ds_buying.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Buying Information"]);
      return;
    }
  }

  // if ($c.win.confirm) {
  //     if (!$c.win.confirm(E_MSG_CM_CRM_001)) return; // 저장하시겠습니까?
  // }

  if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) return; //저장하시겠습니까?

  if (ds_retrieveTariff) ds_retrieveTariff.removeAll();
  if (ds_resultTariff) ds_resultTariff.removeAll();
  ds_retrieveTariff.insertRow(0);
  var kcomcd = scwin.hd_kcomcd || "";
  var apdt = ed_hhetd ? ed_hhetd.getValue() : "";
  var item = scwin.hd_hhitem || "";
  var userId = scwin.userId || "";
  var dang = scwin.hd_hhdanggb || "";
  var comm = scwin.hd_commcustomer || "";

  // 탭별 세팅
  if (scwin.tabNo == "0") {
    // Selling
    ds_retrieveTariff.setCellData(0, "fgubn", "1");
    ds_retrieveTariff.setCellData(0, "customer", ed_hhactcust ? ed_hhactcust.getValue() : "");
    ds_retrieveTariff.setCellData(0, "partner", "");
    ds_retrieveTariff.setCellData(0, "liner", ed_hhliner ? ed_hhliner.getValue() : "");
    ds_retrieveTariff.setCellData(0, "transTariffYn", "Y");
    ds_retrieveTariff.setCellData(0, "blNo", cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : "");
    ds_retrieveTariff.setCellData(0, "mhno", cnd_lc_mhno ? cnd_lc_mhno.getValue() : "");
  } else if (scwin.tabNo == "1") {
    // Partner
    ds_retrieveTariff.setCellData(0, "fgubn", "3");
    ds_retrieveTariff.setCellData(0, "customer", "");
    ds_retrieveTariff.setCellData(0, "partner", ed_hhagent ? ed_hhagent.getValue() : "");
    ds_retrieveTariff.setCellData(0, "liner", "");
    ds_retrieveTariff.setCellData(0, "transTariffYn", "N");
    ds_retrieveTariff.setCellData(0, "blNo", "");
    ds_retrieveTariff.setCellData(0, "mhno", "");
  } else if (scwin.tabNo == "2") {
    // Buying
    ds_retrieveTariff.setCellData(0, "fgubn", "2");
    ds_retrieveTariff.setCellData(0, "customer", ed_hhactcust ? ed_hhactcust.getValue() : "");
    ds_retrieveTariff.setCellData(0, "partner", "");
    ds_retrieveTariff.setCellData(0, "liner", ed_hhliner ? ed_hhliner.getValue() : "");
    ds_retrieveTariff.setCellData(0, "transTariffYn", "Y");
    ds_retrieveTariff.setCellData(0, "blNo", cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : "");
    ds_retrieveTariff.setCellData(0, "mhno", cnd_lc_mhno ? cnd_lc_mhno.getValue() : "");
  }

  // 공통 세팅
  ds_retrieveTariff.setCellData(0, "kcomcd", kcomcd);
  ds_retrieveTariff.setCellData(0, "apdt", apdt);
  ds_retrieveTariff.setCellData(0, "loading", ed_hhlodcd ? ed_hhlodcd.getValue() : "");
  ds_retrieveTariff.setCellData(0, "discharge", ed_hhdisccd ? ed_hhdisccd.getValue() : "");
  ds_retrieveTariff.setCellData(0, "item", item);
  ds_retrieveTariff.setCellData(0, "container1", cnt1);
  ds_retrieveTariff.setCellData(0, "container2", cnt2);
  ds_retrieveTariff.setCellData(0, "container3", cnt3);
  ds_retrieveTariff.setCellData(0, "container4", cnt4);
  ds_retrieveTariff.setCellData(0, "cbgubn", "C");
  ds_retrieveTariff.setCellData(0, "incoterm", "");
  ds_retrieveTariff.setCellData(0, "userid", userId);
  ds_retrieveTariff.setCellData(0, "dangerous", dang);
  ds_retrieveTariff.setCellData(0, "commcustomer", comm);
  ds_retrieveTariff.setCellData(0, "flag", "1");
  scwin._tariffMode = "TARIFF_ALL";
  scwin._tariffTab = scwin.tabNo;
  $c.sbm.execute($p, sbm_retrieveTariff);
};

//-------------------------------------------------------------------------
// sbm_retrieveTariff onsubmitdone
// - BUYING_RATE: 결과 1건의 amount → buying row pchsUpr
// - TARIFF_ALL : 탭별 결과만큼 row 생성 후 금액/환율 처리, chgWt==0 삭제
//-------------------------------------------------------------------------
scwin.sbm_retrieveTariff_onsubmitdone = async function (e) {
  if (!ds_resultTariff || ds_resultTariff.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
    scwin._tariffMode = "";
    scwin._tariffTab = "";
    scwin._tariffRow = -1;
    return;
  }

  // 단건 Buying Rate 모드
  if (scwin._tariffMode == "BUYING_RATE") {
    var b = scwin._tariffRow;
    var amount = ds_resultTariff.getCellData(0, "amount");
    if (b != undefined && b != null && b >= 0) {
      ds_buying.setCellData(b, "pchsUpr", amount);
    }
    scwin._tariffMode = "";
    scwin._tariffRow = -1;
    return;
  }

  // Tariff All 모드
  if (scwin._tariffMode == "TARIFF_ALL") {
    // Selling
    if (scwin._tariffTab == "0") {
      for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
        scwin.f_addRow(1);
        var r = ds_selling.getRowCount() - 1;
        ds_selling.setCellData(r, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd"));
        await scwin.f_PopUpGrid("SellingFcode", r, "T", "F", "retrieveTariff_onsubmit");
      }
      for (var i = ds_selling.getRowCount() - 1; i >= 0; i--) {
        if (String(ds_selling.getCellData(i, "chgWt") || "") == "0") {
          ds_selling.deleteRow(i);
        }
      }
    }

    // Partner
    if (scwin._tariffTab == "1") {
      for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
        scwin.f_addRow(2);
        var r = ds_partner.getRowCount() - 1;
        ds_partner.setCellData(r, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd"));
        ds_partner.setCellData(r, "drcrCls", "D");
        await scwin.f_PopUpGrid("PartnerFcode", r, "T", "F");
        ds_partner.setCellData(r, "crcCd", ds_resultTariff.getCellData(i, "crcCd"));
        ds_partner.setCellData(r, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit"));
        await scwin.f_packageRatePartnerLoading(r, "");
        ds_partner.setCellData(r, "sellUpr", ds_resultTariff.getCellData(i, "amount"));
        await scwin.f_partnerAmtFcrc(r, "", "");
        await scwin.f_ExRatePartnerGridLoading();
        await scwin.f_partnerAmt(r, "", "");
        scwin.f_partnerUsdAmt(r, "", "");
      }
      for (var i = ds_partner.getRowCount() - 1; i >= 0; i--) {
        if (String(ds_partner.getCellData(i, "chgWt") || "") == "0") {
          ds_partner.deleteRow(i);
        }
      }
    }

    // Buying
    if (scwin._tariffTab == "2") {
      for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
        scwin.f_addRow(3);
        var r = ds_buying.getRowCount() - 1;
        ds_buying.setCellData(r, "pchsTyp", "1");
        ds_buying.setCellData(r, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd"));
        scwin.f_PopUpGrid("BuyingFcode", r, "T", "F");
        ds_buying.setCellData(r, "crcCd", ds_resultTariff.getCellData(i, "crcCd"));
        ds_buying.setCellData(r, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit"));
        scwin.f_packageRateBuyingLoading(r, "");
        ds_buying.setCellData(r, "pchsUpr", ds_resultTariff.getCellData(i, "amount"));
        scwin.f_buyingAmtFcrc(r, "", "");
        scwin.f_ExRateBuyingGridLoading();
        scwin.f_buyingAmt(r, "", "");
        scwin.f_buyingVat(r, "", "");
        scwin.f_buyingUsdAmt(r, "", "");
      }
      for (var i = ds_buying.getRowCount() - 1; i >= 0; i--) {
        if (String(ds_buying.getCellData(i, "chgWt") || "") == "0") {
          ds_buying.deleteRow(i);
        }
      }
    }
    scwin._tariffMode = "";
    scwin._tariffTab = "";
    return;
  }
  scwin._tariffMode = "";
  scwin._tariffTab = "";
  scwin._tariffRow = -1;
};

//-------------------------------------------------------------------------
// Ex-rate Change 가져오기 (Selling/Partner/Buying)
// - certiNo/pchsCertiNo 없는 행만 대상
// - 환종이 헤더 통화(ed_hhcur)와 동일한 행만 환율 적용
// - 환율 변경 후 금액/부가세/달러 환산 재계산
//-------------------------------------------------------------------------
scwin.f_exRateChange = async function () {
  var cur = ed_hhcur.getValue();
  var rate = ed_hhexrate.getValue();
  if (scwin.tabNo == "0") {
    // Selling
    if (ds_selling.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]);
      return;
    }
    if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
      for (var i = 0; i < ds_selling.getRowCount(); i++) {
        var cert = String(ds_selling.getCellData(i, "certiNo") || "").trim();
        if (cert != "") continue;
        if (String(ds_selling.getCellData(i, "crcCd") || "") == cur) {
          ds_selling.setCellData(i, "exRate", rate);
          scwin.f_sellingAmt(i, "", "");
          scwin.f_sellingVat(i, "", "");
          scwin.f_sellingUsdAmt(i, "", "");
        }
      }
    }
  } else if (scwin.tabNo == "1") {
    // Partner
    if (ds_partner.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Partner Information"]);
      return;
    }
    if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
      for (var i = 0; i < ds_partner.getRowCount(); i++) {
        var cert = String(ds_partner.getCellData(i, "certiNo") || "").trim();
        if (cert != "") continue;
        if (String(ds_partner.getCellData(i, "crcCd") || "") == cur) {
          ds_partner.setCellData(i, "exRate", rate);
          scwin.f_partnerAmt(i, "", "");
          scwin.f_partnerUsdAmt(i, "", "");
        }
      }
    }
  } else if (scwin.tabNo == "2") {
    // Buying
    if (!ds_buying || ds_buying.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Buying Information"]);
      return;
    }
    if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
      for (var i = 0; i < ds_buying.getRowCount(); i++) {
        var cert = String(ds_buying.getCellData(i, "pchsCertiNo") || "").trim();
        if (cert != "") continue;
        if (String(ds_buying.getCellData(i, "crcCd") || "") == cur) {
          ds_buying.setCellData(i, "exRate", rate);
          scwin.f_buyingAmt(i, "", "");
          scwin.f_buyingVat(i, "", "");
          scwin.f_buyingUsdAmt(i, "", "");
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
// Customer Change (WebSquare)
// - showModalDialog -> $c.win.openPopup + callback
// - GAUCE dataset(1-base) -> DataList(0-base)
//-------------------------------------------------------------------------
scwin.f_CustomerChange = async function (disGubun) {
  var rtnList = {};
  let opts = {
    id: "pupup",
    popupName: "CustomerChange",
    modal: true,
    type: "browserPopup",
    width: 460,
    height: 280,
    title: "Customer Change"
  };
  rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonCustomerChange.xml", opts);
  if (!$c.gus.cfIsNull($p, rtnList)) {
    if (rtnList[0] == "N/A") {
      if (scwin.tabNo == "0") {
        // Selling 
        if (ds_selling.getRowCount() == 0) {
          await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]); //  @이(가) 존재하지 않습니다.		
        } else {
          if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
            //저장하시겠습니까?	
            for (var i = 0; i < ds_selling.getRowCount(); i++) {
              if (ds_selling.getCellData(i, "certiNo").trim() == "") {
                if (ds_selling.getCellData(i, "bilgClntNo") == rtnList[1]) {
                  ds_selling.setCellData(i, "bilgClntNo", rtnList[3]);
                  ds_selling.setCellData(i, "bilgClntNm", rtnList[4]);
                }
              }
            }
          }
        }
      } else if (scwin.tabNo == "1") {
        //partner
        if (ds_partner.getRowCount() == 0) {
          await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Partner Information"]); //  @이(가) 존재하지 않습니다.	
        } else {
          if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
            //저장하시겠습니까?	
            for (var i = 0; i < ds_partner.getRowCount(); i++) {
              if (ds_partner.getCellData(i, "certiNo").trim() == "") {
                if (ds_partner.getCellData(i, "bilgClntNo") == rtnList[1]) {
                  ds_partner.setCellData(i, "bilgClntNo", rtnList[3]);
                  ds_partner.setCellData(i, "bilgClntNm", rtnList[4]);
                }
              }
            }
          }
        }
      } else if (scwin.tabNo == "2") {
        // Buying 
        if (ds_buying.getRowCount() == "0") {
          await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Buying Information"]); //  @이(가) 존재하지 않습니다.	
        } else {
          if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
            //저장하시겠습니까?	
            for (var i = 0; i < ds_buying.getRowCount(); i++) {
              if (ds_buying.getCellData(i, "pchsCertiNo").trim() == "") {
                if (ds_buying.getCellData(i, "pchsClntNo") == rtnList[1]) {
                  ds_buying.setCellData(i, "pchsClntNo", rtnList[3]);
                  ds_buying.setCellData(i, "pchsClntNm", rtnList[4]);
                }
              }
            }
          }
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
// Customer Change callback
// ret 예시(원본 rtnList 매핑):
// ret.result   == "N/A" (원본 rtnList[0])
// ret.oldCode  == rtnList[1]
// ret.oldName  == rtnList[2]
// ret.newCode  == rtnList[3]
// ret.newName  == rtnList[4]
//-------------------------------------------------------------------------
scwin.f_CustomerChange_callback = async function (ret) {
  if (!ret) return;

  // 원본: if (rtnList[0] == "N/A")
  if (String(ret.result || "") != "N/A") return;
  var oldCode = String(ret.oldCode || "");
  var newCode = String(ret.newCode || "");
  var newName = String(ret.newName || "");

  // 탭별 처리
  if (scwin.tabNo == "0") {
    // Selling
    if (ds_selling.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) {
      return;
    }
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
      // 원본: certiNo가 비어있을 때만
      var certiNo = String(ds_selling.getCellData(i, "certiNo") || "").trim();
      if (certiNo != "") continue;
      if (String(ds_selling.getCellData(i, "bilgClntNo") || "") == oldCode) {
        ds_selling.setCellData(i, "bilgClntNo", newCode);
        ds_selling.setCellData(i, "bilgClntNm", newName);
      }
    }
  } else if (tabNo == "1") {
    // Partner
    if (ds_partner.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Partner Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) {
      return;
    }
    for (var j = 0; j < ds_partner.getRowCount(); j++) {
      var certiNo2 = String(ds_partner.getCellData(j, "certiNo") || "").trim();
      if (certiNo2 != "") continue;
      if (String(ds_partner.getCellData(j, "bilgClntNo") || "") == oldCode) {
        ds_partner.setCellData(j, "bilgClntNo", newCode);
        ds_partner.setCellData(j, "bilgClntNm", newName);
      }
    }
  } else if (tabNo == "2") {
    // Buying
    if (ds_buying.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Buying Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) {
      return;
    }
    for (var k = 0; k < ds_buying.getRowCount(); k++) {
      // 원본: pchsCertiNo가 비어있을 때만
      var pchsCertiNo = String(ds_buying.getCellData(k, "pchsCertiNo") || "").trim();
      if (pchsCertiNo != "") continue;
      if (String(ds_buying.getCellData(k, "pchsClntNo") || "") == oldCode) {
        ds_buying.setCellData(k, "pchsClntNo", newCode);
        ds_buying.setCellData(k, "pchsClntNm", newName);
      }
    }
  }
};

//-------------------------------------------------------------------------
// tariff 버튼: grid에 package, rate 계산 (Selling)
//-------------------------------------------------------------------------
scwin.f_packageRateSellingLoading = function (row, colid) {
  var r = typeof row == "number" ? row : ds_selling.getRowPos ? ds_selling.getRowPos() : 0;
  var gwgt = Number(ed_hhgwgt ? ed_hhgwgt.getValue() : 0); // kg
  var msr = Number(ed_hhmsr ? ed_hhmsr.getValue() : 0); // cbm
  var v_wgt = gwgt / 1000;
  var v_msr = msr;
  var v_wgtR = Math.ceil(v_wgt);
  var v_msrR = Math.ceil(v_msr);
  var eng = ds_selling.getCellData(r, "fareEngCd");
  var unit = ds_selling.getCellData(r, "fareUnit");
  var wgt = eng == "WFG" ? v_wgtR : v_wgt;
  var msrVal = eng == "WFG" ? v_msrR : v_msr;
  if (unit == "WGT" || unit == "M/T") {
    ds_selling.setCellData(r, "chgWt", eng == "WFG" ? Math.ceil(gwgt) : gwgt);
  } else if (unit == "R/T") {
    if (v_wgt > v_msr) {
      ds_selling.setCellData(r, "chgWt", wgt < 1 ? 1 : wgt);
    } else {
      ds_selling.setCellData(r, "chgWt", msrVal < 1 ? 1 : msrVal);
    }
  } else if (unit == "CBM") {
    ds_selling.setCellData(r, "chgWt", msrVal < 1 ? 1 : msrVal);
  } else if (unit == "CASE") {
    ds_selling.setCellData(r, "chgWt", "1");
  } else {
    if (unit == (ed_hhcnt1type ? ed_hhcnt1type.getValue() : "")) ds_selling.setCellData(r, "chgWt", ed_hhcnt1 ? ed_hhcnt1.getValue() : "");else if (unit == (ed_hhcnt2type ? ed_hhcnt2type.getValue() : "")) ds_selling.setCellData(r, "chgWt", ed_hhcnt2 ? ed_hhcnt2.getValue() : "");else if (unit == (ed_hhcnt3type ? ed_hhcnt3type.getValue() : "")) ds_selling.setCellData(r, "chgWt", ed_hhcnt3 ? ed_hhcnt3.getValue() : "");else if (unit == (ed_hhcnt4type ? ed_hhcnt4type.getValue() : "")) ds_selling.setCellData(r, "chgWt", ed_hhcnt4 ? ed_hhcnt4.getValue() : "");
  }
};

