//-------------------------------------------------------------------------
// Result date Change
//-------------------------------------------------------------------------
scwin.f_ResultdateChange = async function () {
  const opt = {
    width: "460",
    height: "280",
    id: "popResultDateChange",
    popupName: "Result Date Change",
    title: "Result Date Change"
  };
  const data = {}; // 기존 arrParm

  const rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonResultDateChange.xml", opt, data);

  // rtnList[0] = "N/A", rtnList[1] = ed_resultdt 값
  if (rtnList && rtnList[0] === "N/A") {
    scwin.f_GridResultdateChange(rtnList);
  }
};
scwin.f_GridResultdateChange = async function (rtnList) {
  var tabIdx = dma_retrieve.get("tabIndex") || scwin.tabNo || "";
  var dt = rtnList[1];
  if (tabIdx == "0" || tabIdx == "") {
    // Selling
    if (!ds_selling || ds_selling.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) return;
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
      var cert = String(ds_selling.getCellData(i, "certiNo") || "").trim();
      if (cert == "") {
        ds_selling.setCellData(i, "rsltsStdDt", dt);
      }
    }
  } else if (tabIdx == "1") {
    // Partner
    if (!ds_partner || ds_partner.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Partner Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) return;
    for (var i = 0; i < ds_partner.getRowCount(); i++) {
      var cert = String(ds_partner.getCellData(i, "certiNo") || "").trim();
      if (cert == "") {
        ds_partner.setCellData(i, "rsltsStdDt", dt);
      }
    }
  } else if (tabIdx == "2") {
    // Buying
    if (!ds_buying || ds_buying.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Buying Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001)))) return;
    for (var i = 0; i < ds_buying.getRowCount(); i++) {
      var cert = String(ds_buying.getCellData(i, "pchsCertiNo") || "").trim();
      if (cert == "") {
        ds_buying.setCellData(i, "rsltsStdDt", dt);
      }
    }
  }
};

