//-------------------------------------------------------------------------
// tab List 값을 ds_houseblList 컬럼으로 변경 (gubun: "0"/"1"/"2")
// 원본의 헤더 재설정/getAllJSON() 부분은 프로젝트 유틸에 맞게 별도 구현 필요
//-------------------------------------------------------------------------
scwin.f_chgGridColumnToHouseBlDs = async function (gubun, ds) {
  ds_tmp.removeAll();
  ds_tmp.setJSON(ds.getAllJSON());
  ds.removeAll();
  ds.setJSON(ds_tmp.getAllJSON());
  for (var i = 0; i < ds.getRowCount(); i++) {
    ds.setCellData(i, "kcomcd", scwin.hd_kcomcd);
    ds.setCellData(i, "blNo", cnd_ed_hhblno.getValue()); //update일때.
    ds.setCellData(i, "mhno", cnd_lc_mhno.getValue()); //update일때.
    ds.setCellData(i, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, "odrNo"));
    ds.setCellData(i, "mblHblCls", "H"); //house/master       
    ds.setCellData(i, "seaAirCls", "S"); // sea/air
    ds.setCellData(i, "ppccCls", scwin.hd_hhpcgb); //pp/cc                                         
    ds.setCellData(i, "inpid", scwin.userId);
    if (gubun == "0") {
      ds.setCellData(i, "bilgClntNo", ed_hhactcust.getValue()); //CUSTOMER   
      ds.setCellData(i, "bilgClntNm", ds_houseblList.getRowJSON(0).hhactcustnm); //txt_hhactcustnm.getValue());   //CUSTOMER name   
      await scwin.f_sellingUnitLoading();
      ds.setCellData(i, "locPtnCls", "1"); //국내 : 1, 해외 :2 
    } else if (gubun == "1") {
      ds.setCellData(i, "bilgClntNo", ed_hhagent.getValue());
      ds.setCellData(i, "bilgClntNm", ds_houseblList.getRowJSON(0).hhagentnm); //txt_hhagentnm.getValue());   //partner name 
      await scwin.f_partnerUnitLoading();
      ds.setCellData(i, "locPtnCls", "2"); //국내 : 1, 해외 :2 
    } else if (gubun == "2") {
      await scwin.f_buyingUnitLoading();
      ds.setCellData(i, "locPtnCls", "1"); //국내 : 1, 해외 :2   
    }
    ds.setCellData(i, "rsltsStdDt", scwin.hd_creadyDt); //실적일 
    ds.setCellData(i, "exRateTyp", lc_hhexgb.getValue()); //exgb

    //Gause Status를 Insert로 변경한다.
    //ds.UserStatus(i) = 1;
    ds.modifyRowStatus(i, "C");
  }

  //unit처리.
  if (gubun == "0") {
    scwin.f_SellingSum();
  } else if (gubun == "1") {
    scwin.f_PartnerSum();
  } else if (gubun == "2") {
    scwin.f_BuyingSum();
  }
};

