//-------------------------------------------------------------------------
// Result Date의 회계마감 여부를 체크하는 함수 : 회계마감된 월로는 실적일자 입력 불가능 (WebSquare 변환)
// 적용 규칙
// - RowStatus/NameValue/CountRow -> getRowCount/getCellData/setCellData/getRowStatus
// - cf* 함수 -> $c.gus.cf* 로 호출
// - cfAlertMsg -> await $c.win.alert(...)
//  (cfJobCloseYN 도 cf* 이므로 $c.gus.cfJobCloseYN 로 변환)
//-------------------------------------------------------------------------
scwin.f_JobCloseYn = async function () {
  var preWrkNo = "FI01"; // 월 마감코드

  //Selling List 실적일자 회계마감 여부 CHECK	 
  var minRsltsDt = scwin.strCurDate.substr(0, 6);
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if (ds_selling.getRowStatus(i) == "C") {
      //운임 신규 생성일때
      if (ds_selling.getCellData(i, "rsltsStdDt").substr(0, 6) < minRsltsDt) {
        minRsltsDt = ds_selling.getCellData(i, "rsltsStdDt").substr(0, 6);
      }
    }
  }
  var rsltsDt = minRsltsDt;
  var isCloseDepr = await udc_comChkRes.cfJobCloseYN("CUR", rsltsDt, "00", preWrkNo, "0", "", "", '000');
  if (isCloseDepr == "2" || isCloseDepr == "DNF") {
    await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nSelling List Result Date를 확인하세요.");
    return false;
  }

  //Partner List 실적일자 회계마감 여부 CHECK	 
  var minRsltsDt = scwin.strCurDate.substr(0, 6);
  for (var i = 0; i < ds_partner.getRowCount(); i++) {
    if (ds_partner.getRowStatus(i) == "C") {
      //운임 신규 생성일때
      if (ds_partner.getCellData(i, "rsltsStdDt").substr(0, 6) < minRsltsDt) {
        minRsltsDt = ds_partner.getCellData(i, "rsltsStdDt").substr(0, 6);
      }
    }
  }
  var rsltsDt = minRsltsDt;
  var isCloseDepr = await udc_comChkRes.cfJobCloseYN("CUR", rsltsDt, "00", preWrkNo, "0", "", "", '000');
  if (isCloseDepr == "2" || isCloseDepr == "DNF") {
    await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nPartner List Result Date를 확인하세요.");
    return false;
  }

  //Buying List 실적일자 회계마감 여부 CHECK	 
  var minRsltsDt = scwin.strCurDate.substr(0, 6);
  for (var i = 0; i < ds_buying.getRowCount(); i++) {
    if (ds_buying.getRowStatus(i) == "C") {
      //운임 신규 생성일때
      if (ds_buying.getCellData(i, "rsltsStdDt").substr(0, 6) < minRsltsDt) {
        minRsltsDt = ds_buying.getCellData(i, "rsltsStdDt").substr(0, 6);
      }
    }
  }
  var rsltsDt = minRsltsDt;
  var isCloseDepr = await udc_comChkRes.cfJobCloseYN("CUR", rsltsDt, "00", preWrkNo, "0", "", "", '000');
  if (isCloseDepr == "2" || isCloseDepr == "DNF") {
    await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nBuying List Result Date를 확인하세요.");
    return false;
  }
  return true;
};

