//==========================
// Currency 코드 존재 체크 (ds_currencyCode에 code 컬럼이 있다고 가정)
// - ds_currencyCode.ValueRow(1, code) 대체
//==========================
scwin._existsCurrency = function (code) {
  code = String(code || "").trim();
  if (!code) return false;
  var rc = typeof ds_currencyCode.getRowCount == "function" ? ds_currencyCode.getRowCount() : 0;
  for (var r = 0; r < rc; r++) {
    // ds_currencyCode의 컬럼명이 프로젝트마다 다를 수 있음: "CODE" / "code" / "col1" 등
    var c1 = String(ds_currencyCode.getCellData(r, "CODE") || "").trim();
    var c2 = String(ds_currencyCode.getCellData(r, "code") || "").trim();
    var c3 = String(ds_currencyCode.getCellData(r, "col1") || "").trim();
    if (code == c1 || code == c2 || code == c3) return true;
  }
  return false;
};

//==========================
// ds_selling : oncolumnchange (WebSquare)
//==========================
scwin.ds_selling_oncelldatachange = async function (info) {
  var row = info.rowIndex;
  var colid = info.colID;

  // Currency event
  if (colid == "crcCd") {
    if (ds_selling.getCellData(row, "crcCd") != "") {
      var idxArr = ds_currencyCode.getMatchedIndex(0, ds_selling.getCellData(row, "crcCd"));
      if (!(idxArr.length > 0)) {
        // 값이 없을때
        ds_selling.setCellData(row, "exRate", "");
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Currency Information"]); //  @이(가) 존재하지 않습니다.
      } else {
        if (ds_selling.getCellData(row, "crcCd") != "KRW") {
          await scwin.f_ExRateSellingGridLoading();
        }
      }
    } else {
      return;
    }
  }

  // sum값 call
  if (colid == "sellAmtFcrc" || colid == "sellAmt" || colid == "vatAmt") {
    await scwin.f_SellingSum();
  }
};

//==========================
// ds_partner : oncolumnchange (WebSquare)
//==========================
scwin.ds_partner_oncelldatachange = async function (info) {
  var row = info.rowIndex;
  var col = info.colID;

  // Currency event
  if (col == "crcCd") {
    if (ds_partner.getCellData(row, "crcCd") != "") {
      var STR = ds_currencyCode.getMatchedIndex(0, ds_partner.getCellData(row, "crcCd"));
      if (!(STR.length > 0)) {
        // 값이 없을때
        ds_partner.setCellData(row, "exRate", "");
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Currency Information"]); //  @이(가) 존재하지 않습니다.
      } else {
        if (ds_partner.getCellData(row, "crcCd") != "KRW") {
          await scwin.f_ExRatePartnerGridLoading();
        }
      }
    } else {
      return;
    }
  }

  // sum값 call
  if (col == "sellAmtFcrc" || col == "sellAmt") {
    scwin.f_PartnerSum();
  }
};

//==========================
// ds_buying : oncolumnchange (WebSquare)
//==========================
scwin.ds_buying_oncelldatachange = async function (info) {
  var row = info.rowIndex;
  var col = info.colID;

  // Currency event
  if (col == "crcCd") {
    if (ds_buying.getCellData(row, "crcCd") != "") {
      var STR = ds_currencyCode.getMatchedIndex(0, ds_buying.getCellData(row, "crcCd"));
      if (!(STR.length > 0)) {
        // 값이 없을때
        ds_buying.setCellData(row, "exRate", "");
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Currency Information"]); //  @이(가) 존재하지 않습니다.
      } else {
        if (ds_buying.getCellData(row, "crcCd") != "KRW") {
          await scwin.f_ExRateBuyingGridLoading();
        }
      }
    } else {
      return;
    }
  }

  // sum값 call
  if (col == "pchsAmtFcrc" || col == "pchsAmt" || col == "vat") {
    scwin.f_BuyingSum();
  }
};

//==========================
// header checkbox 공통 처리
//==========================
scwin._headCheckApply = function (ds, checked) {
  var isOn = checked == true || checked == "1" || String(checked).toLowerCase() == "true";
  var v = isOn ? "T" : "F";
  var rc = ds.getRowCount();
  for (var r = 0; r < rc; r++) {
    ds.setCellData(r, "chk", v);
  }
};
scwin.tac_tabMain_onchange = function (tabId, index, userTabId) {
  if (index == 0) {
    scwin.f_SellingSum();
    gr_selling.setFocusedCell(0, 0);
  } else if (index == 1) {
    scwin.f_PartnerSum();
    gr_partner.setFocusedCell(0, 0);
  } else if (index == 2) {
    scwin.f_BuyingSum();
    gr_buying.setFocusedCell(0, 0);
  }
  scwin.f_selectTabMenu(index);
};

